INSERT INTO `v1_f19e1b2cb05ff78cee95de4f3ef94fc0488911293dd9d71586f83eb7343b12a4` VALUES (2, 24001, 102301, 2, 10046, 0.0, 401, 0.0, 24, "2020/07/31 12:00:00", 0.0, "アヤネ", "2030/12/17 14:59:59", "やったね、ぷうきち！\nこれならお兄ちゃんたちの\nお手本になれたよね！");
INSERT INTO `v1_f19e1b2cb05ff78cee95de4f3ef94fc0488911293dd9d71586f83eb7343b12a4` VALUES (2, 24002, 102301, 1, 10046, 0.0, 402, 0.0, 24, "2020/07/31 12:00:00", 2.21, "アヤネ", "2030/12/17 14:59:59", "私たちの勝ちだね！\nぷうきちと一緒なら\nどんなボールでも\nホームランを打ってみせるよ！");
INSERT INTO `v1_f19e1b2cb05ff78cee95de4f3ef94fc0488911293dd9d71586f83eb7343b12a4` VALUES (2, 24003, 102301, 2, 10046, 0.0, 403, 0.0, 24, "2020/07/31 12:00:00", 0.0, "アヤネ", "2030/12/17 14:59:59", "やったやったぁ！\nお兄ちゃん、見ててくれた？\n私、すっごくがんばったよ！");
INSERT INTO `v1_f19e1b2cb05ff78cee95de4f3ef94fc0488911293dd9d71586f83eb7343b12a4` VALUES (1, 24004, 192201, 2, 10046, 0.0, 701, 0.0, 24, "2020/07/31 12:00:00", 1.99, "アサヒ", "2030/12/17 14:59:59", "特訓の成果が出たみたいだ！\nもっと練習を重ねて\nこの調子で上達していこう！");
INSERT INTO `v1_f19e1b2cb05ff78cee95de4f3ef94fc0488911293dd9d71586f83eb7343b12a4` VALUES (2, 24005, 192201, 1, 10046, 0.0, 702, 0.0, 24, "2020/07/31 12:00:00", 2.21, "アサヒ", "2030/12/17 14:59:59", "よし、いい感じだ！\nキャプテンとしての仕事は\nきっちり果たせそうだよ");
INSERT INTO `v1_f19e1b2cb05ff78cee95de4f3ef94fc0488911293dd9d71586f83eb7343b12a4` VALUES (1, 24006, 192201, 2, 10046, 0.0, 703, 0.0, 24, "2020/07/31 12:00:00", 3.33, "アサヒ", "2030/12/17 14:59:59", "試合に向けて\nいい感覚を掴めた気がするよ！\nこのまま一気に全国大会だ！");
INSERT INTO `v1_f19e1b2cb05ff78cee95de4f3ef94fc0488911293dd9d71586f83eb7343b12a4` VALUES (2, 24007, 192301, 2, 10046, 0.0, 801, 0.0, 24, "2020/07/31 12:00:00", 0.0, "部員３", "2030/12/17 14:59:59", "このくらい余裕だ\nオレたちは全国大会を\n目指してるんだからな");
INSERT INTO `v1_f19e1b2cb05ff78cee95de4f3ef94fc0488911293dd9d71586f83eb7343b12a4` VALUES (2, 24008, 192301, 1, 10046, 0.0, 802, 0.0, 24, "2020/07/31 12:00:00", 2.68, "部員３", "2030/12/17 14:59:59", "オレだって\nビーチベースボール選手だ\nどんな球だろうが\n全部スタンドまで飛ばしてやる");
INSERT INTO `v1_f19e1b2cb05ff78cee95de4f3ef94fc0488911293dd9d71586f83eb7343b12a4` VALUES (2, 24009, 192301, 2, 10046, 0.0, 803, 0.0, 24, "2020/07/31 12:00:00", 0.0, "部員３", "2030/12/17 14:59:59", "いい感じだ\nこれなら試合でも活躍できそうだ\n大暴れしてやる！");
INSERT INTO `v1_f19e1b2cb05ff78cee95de4f3ef94fc0488911293dd9d71586f83eb7343b12a4` VALUES (1, 24010, 192501, 1, 10046, 0.0, 501, 0.0, 24, "2020/07/31 12:00:00", 0.0, "", "2030/12/17 14:59:59", "やった！");
INSERT INTO `v1_f19e1b2cb05ff78cee95de4f3ef94fc0488911293dd9d71586f83eb7343b12a4` VALUES (1, 24011, 192501, 1, 10046, 0.0, 502, 0.0, 24, "2020/07/31 12:00:00", 0.0, "", "2030/12/17 14:59:59", "勝ったよ！");
INSERT INTO `v1_f19e1b2cb05ff78cee95de4f3ef94fc0488911293dd9d71586f83eb7343b12a4` VALUES (1, 24012, 192501, 1, 10046, 0.0, 503, 0.0, 24, "2020/07/31 12:00:00", 0.0, "", "2030/12/17 14:59:59", "いい調子！");
INSERT INTO `v1_f19e1b2cb05ff78cee95de4f3ef94fc0488911293dd9d71586f83eb7343b12a4` VALUES (2, 24013, 113501, 6, 10046, 0.0, 111, 0.0, 24, "2020/07/31 12:00:00", 5.33, "ミサト", "2030/12/17 14:59:59", "あら～…もしかして\n勝っちゃったのかしら？\nみんなの練習を見ていたから\nかもしれないわね");
INSERT INTO `v1_f19e1b2cb05ff78cee95de4f3ef94fc0488911293dd9d71586f83eb7343b12a4` VALUES (2, 24014, 113501, 1, 10046, 0.0, 112, 0.0, 24, "2020/07/31 12:00:00", 6.85, "ミサト", "2030/12/17 14:59:59", "みんなの力になりたくて\n先生も頑張ってみました～！\nうまく投げられたみたいで\nよかったわ～！");
INSERT INTO `v1_f19e1b2cb05ff78cee95de4f3ef94fc0488911293dd9d71586f83eb7343b12a4` VALUES (2, 24015, 113501, 1, 10046, 0.0, 113, 0.0, 24, "2020/07/31 12:00:00", 3.0, "ミサト", "2030/12/17 14:59:59", "練習お疲れさま～！\n先生も協力できて\nとってもうれしいわ～♪\n次も頑張りましょうね～！");
INSERT INTO `v1_f19e1b2cb05ff78cee95de4f3ef94fc0488911293dd9d71586f83eb7343b12a4` VALUES (2, 24016, 192401, 1, 10046, 0.0, 611, 0.0, 24, "2020/07/31 12:00:00", 6.11, "ダイチ", "2030/12/17 14:59:59", "まだ練習が足りねえみてえだな\nこれっぽっちも本気で\n投げてねえっつーの\nもう一回やんぞ！");
INSERT INTO `v1_f19e1b2cb05ff78cee95de4f3ef94fc0488911293dd9d71586f83eb7343b12a4` VALUES (2, 24017, 192401, 1, 10046, 0.0, 612, 0.0, 24, "2020/07/31 12:00:00", 6.75, "ダイチ", "2030/12/17 14:59:59", "ふん、当然の結果だな\n俺の球は、誰にも打てねえよ！\nまたやりてえっつーなら\nとことん付き合ってやるぜ！");
INSERT INTO `v1_f19e1b2cb05ff78cee95de4f3ef94fc0488911293dd9d71586f83eb7343b12a4` VALUES (2, 24018, 192401, 2, 10046, 0.0, 613, 0.0, 24, "2020/07/31 12:00:00", 0.0, "ダイチ", "2030/12/17 14:59:59", "おっしゃあ！\nこの勢いで全国に行ってやるぜ！\n全員三振で仕留めてやる！");
INSERT INTO `v1_f19e1b2cb05ff78cee95de4f3ef94fc0488911293dd9d71586f83eb7343b12a4` VALUES (1, 24019, 113401, 2, 10046, 0.0, 211, 0.0, 24, "2020/07/31 12:00:00", 4.52, "ハツネ", "2030/12/17 14:59:59", "きらーん☆\nハツネちゃんの大勝利なのだ～！\nみんながもっと上達できるように\n私もまだまだ頑張るからね！");
INSERT INTO `v1_f19e1b2cb05ff78cee95de4f3ef94fc0488911293dd9d71586f83eb7343b12a4` VALUES (1, 24020, 113401, 2, 10046, 0.0, 212, 0.0, 24, "2020/07/31 12:00:00", 3.89, "ハツネ", "2030/12/17 14:59:59", "やったあ！　私の勝ちだね！\nチアリーダーもピッチャーも\nハツネちゃんに任せてよ！");
INSERT INTO `v1_f19e1b2cb05ff78cee95de4f3ef94fc0488911293dd9d71586f83eb7343b12a4` VALUES (2, 24021, 113401, 1, 10046, 0.0, 213, 0.0, 24, "2020/07/31 12:00:00", 13.49, "ハツネ", "2030/12/17 14:59:59", "よお～し、この調子でもっと\n頑張ろう…と思ったけど\n超能力を使ったから…\n眠くなってきちゃった…すやぁ…");
INSERT INTO `v1_f19e1b2cb05ff78cee95de4f3ef94fc0488911293dd9d71586f83eb7343b12a4` VALUES (2, 24022, 106501, 1, 10046, 0.0, 311, 0.0, 24, "2020/07/31 12:00:00", 3.17, "カヤ", "2030/12/17 14:59:59", "いい勝負だったぜ！\nたぎっちまって\nつい本気で投げちまったよ");
INSERT INTO `v1_f19e1b2cb05ff78cee95de4f3ef94fc0488911293dd9d71586f83eb7343b12a4` VALUES (2, 24023, 106501, 1, 10046, 0.0, 312, 0.0, 24, "2020/07/31 12:00:00", 4.42, "カヤ", "2030/12/17 14:59:59", "どうだ？\nオレ様のボールは熱かっただろ！\nま、でもおまえらの根性も\nなかなかのもんだったぜ");
INSERT INTO `v1_f19e1b2cb05ff78cee95de4f3ef94fc0488911293dd9d71586f83eb7343b12a4` VALUES (1, 24024, 106501, 6, 10046, 0.0, 313, 0.0, 24, "2020/07/31 12:00:00", 2.89, "カヤ", "2030/12/17 14:59:59", "なんだよ、そんなもんか？\nこっちはまだまだ投げたりねえ\nもっと勝負しようぜ！");
INSERT INTO `v1_f19e1b2cb05ff78cee95de4f3ef94fc0488911293dd9d71586f83eb7343b12a4` VALUES (3, 24025, 102301, 4, 10046, 0.0, 421, 0.0, 24, "2020/07/31 12:00:00", 3.71, "アヤネ", "2030/12/17 14:59:59", "あとちょっとだったのに～！\n次こそぷうきちと一緒に\n勝ってみせるからね！");
INSERT INTO `v1_f19e1b2cb05ff78cee95de4f3ef94fc0488911293dd9d71586f83eb7343b12a4` VALUES (1, 24026, 192201, 2, 10046, 0.0, 721, 0.0, 24, "2020/07/31 12:00:00", 5.1, "アサヒ", "2030/12/17 14:59:59", "いい勝負だったね！\nでも、やっぱり悔しいな…\nもっと練習して\n今度は絶対に俺が勝つから！");
INSERT INTO `v1_f19e1b2cb05ff78cee95de4f3ef94fc0488911293dd9d71586f83eb7343b12a4` VALUES (3, 24027, 192301, 1, 10046, 0.0, 821, 0.0, 24, "2020/07/31 12:00:00", 4.34, "部員３", "2030/12/17 14:59:59", "ちっ…あと一歩足りなかったか\n次こそは絶対に勝つから\nそのつもりでいろ");
INSERT INTO `v1_f19e1b2cb05ff78cee95de4f3ef94fc0488911293dd9d71586f83eb7343b12a4` VALUES (1, 24028, 192501, 1, 10046, 0.0, 521, 0.0, 24, "2020/07/31 12:00:00", 0.0, "", "2030/12/17 14:59:59", "いい勝負だったよ\nまたやろうね");
INSERT INTO `v1_f19e1b2cb05ff78cee95de4f3ef94fc0488911293dd9d71586f83eb7343b12a4` VALUES (2, 24029, 113501, 1, 10046, 0.0, 101, -360.0, 24, "2020/07/31 12:00:00", 5.62, "ミサト", "2030/12/17 14:59:59", "とってもよくできました～♪\n頑張ってくれて先生うれしいわ\nこれからも試合に向けて\n練習していきましょうね～");
INSERT INTO `v1_f19e1b2cb05ff78cee95de4f3ef94fc0488911293dd9d71586f83eb7343b12a4` VALUES (2, 24030, 113501, 1, 10046, 0.0, 102, -360.0, 24, "2020/07/31 12:00:00", 9.58, "ミサト", "2030/12/17 14:59:59", "頑張った成果ね～！\nこのまま練習を続ければ\nもっとすごい成績を残せそうよ\n期待してますからね～！");
INSERT INTO `v1_f19e1b2cb05ff78cee95de4f3ef94fc0488911293dd9d71586f83eb7343b12a4` VALUES (2, 24031, 113501, 2, 10046, 0.0, 103, -360.0, 24, "2020/07/31 12:00:00", 0.0, "ミサト", "2030/12/17 14:59:59", "いい子、いい子～♪\n頑張り屋さんのあなたを\nたっくさん褒めてあげますからね");
INSERT INTO `v1_f19e1b2cb05ff78cee95de4f3ef94fc0488911293dd9d71586f83eb7343b12a4` VALUES (1, 24032, 113501, 2, 10046, 0.0, 104, -360.0, 24, "2020/07/31 12:00:00", 9.13, "ミサト", "2030/12/17 14:59:59", "夢に向けて、一歩前進できたわね\nこの調子で、夢を叶えましょう\n目指せ、全国大会～！");
INSERT INTO `v1_f19e1b2cb05ff78cee95de4f3ef94fc0488911293dd9d71586f83eb7343b12a4` VALUES (2, 24033, 113501, 1, 10046, 0.0, 105, -360.0, 24, "2020/07/31 12:00:00", 8.27, "ミサト", "2030/12/17 14:59:59", "絶好調ね～♪\nきっと試合でも大活躍\n間違いなしだわ\n楽しみにしていますからね～！");
